framework_css:
/*
   Driveway & Paving Framework Styles
   Matches the traditional local-trades header/footer aesthetic
   from the provided design.
*/

/* =============================
   CSS RESET / BASELINE
   ============================= */

*, *::before, *::after {
    box-sizing: border-box;
}

html {
    font-size: 16px;
    -webkit-text-size-adjust: 100%;
}

body {
    margin: 0;
    padding: 0;
    font-family: "Source Sans 3", Helvetica, sans-serif;
    font-weight: 400;
    line-height: 1.5;
    color: #FFFFFF;
    background-color: #181F21;
}

img {
    max-width: 100%;
    display: block;
}

a {
    color: inherit;
    text-decoration: none;
}

a:hover,
a:focus {
    text-decoration: none;
}

ul,
ol {
    margin: 0;
    padding: 0;
    list-style: none;
}

h1,
h2,
h3,
h4,
h5,
h6 {
    margin: 0;
    font-family: "Merriweather", Georgia, serif;
    font-weight: 700;
    line-height: 1.2;
}

p {
    margin: 0;
}

button,
input,
select,
textarea {
    font: inherit;
}

/* =============================
   DESIGN SYSTEM VARIABLES
   ============================= */

:root {
    /* Color Palette */
    --color-primary-900: #181F21; /* Deep charcoal header background */
    --color-primary-accent: #E5FF3B; /* Bright neon yellow CTA */

    --color-secondary-100: #C8CF9E; /* Pale green form card */
    --color-secondary-200: #808890; /* Muted grey for secondary text */

    --color-neutral-000: #FFFFFF;
    --color-neutral-800: #4A4F53;

    --color-semantic-success: #5BA86A;
    --color-semantic-error: #D9534F;
    --color-semantic-warning: #F0AD4E;
    --color-semantic-info: #5BC0DE;

    /* Typography */
    --font-heading: "Merriweather", Georgia, serif;
    --font-body: "Source Sans 3", Helvetica, sans-serif;

    --font-size-h1: 42px;
    --font-size-h2: 32px;
    --font-size-h3: 24px;
    --font-size-body: 16px;
    --font-size-small: 13px;

    --font-weight-light: 300;
    --font-weight-regular: 400;
    --font-weight-medium: 500;
    --font-weight-semibold: 600;
    --font-weight-bold: 700;

    --line-height-tight: 1.2;
    --line-height-normal: 1.5;
    --line-height-relaxed: 1.7;

    /* Spacing Scale (base unit: 8px) */
    --space-xxs: 4px;
    --space-xs: 8px;
    --space-sm: 16px;
    --space-md: 24px;
    --space-lg: 32px;
    --space-xl: 48px;
    --space-xxl: 64px;

    /* Layout */
    --container-max-width: 1200px;
    --header-height-desktop: 86px;
    --header-border-color: #2B3437;

    /* Components */
    --btn-radius: 4px;
    --transition-fast: 150ms ease-out;
}

/* =============================
   LAYOUT HELPERS
   ============================= */

.site-wrapper {
    min-height: 100vh;
    display: flex;
    flex-direction: column;
}

.container {
    width: 100%;
    max-width: var(--container-max-width);
    margin: 0 auto;
    padding-left: var(--space-md);
    padding-right: var(--space-md);
}

.site-main {
    flex: 1 0 auto;
    background-color: #111618; /* slightly darker than header, similar to hero overlay */
    padding-top: var(--space-xl);
    padding-bottom: var(--space-xl);
}

/* =============================
   HEADER
   ============================= */

.site-header {
    position: sticky;
    top: 0;
    z-index: 1000;
    background-color: var(--color-primary-900);
    border-bottom: 1px solid var(--header-border-color);
}

.header-inner {
    display: flex;
    align-items: center;
    justify-content: space-between;
    height: var(--header-height-desktop);
    gap: var(--space-lg);
}

/* Branding (text-only logo approximating the design) */

.site-branding {
    display: flex;
    align-items: center;
    flex-shrink: 0;
}

.site-logo-text {
    display: flex;
    flex-direction: column;
    gap: 2px;
}

.site-logo-title {
    font-family: var(--font-heading);
    font-size: 18px;
    letter-spacing: 0.18em;
    text-transform: uppercase;
    color: var(--color-neutral-000);
}

.site-logo-subtitle {
    font-family: var(--font-body);
    font-size: 10px;
    letter-spacing: 0.25em;
    text-transform: uppercase;
    color: var(--color-secondary-200);
}

/* Navigation */

.header-navigation {
    display: flex;
    align-items: center;
    justify-content: flex-end;
    flex: 1 1 auto;
    gap: var(--space-lg);
}

.main-nav {
    flex: 1 1 auto;
}

.nav-list {
    display: flex;
    align-items: center;
    justify-content: flex-end;
    gap: var(--space-lg);
}

.nav-item {
    position: relative;
}

.nav-link {
    font-family: var(--font-body);
    font-size: 15px;
    font-weight: var(--font-weight-regular);
    color: var(--color-neutral-000);
    letter-spacing: 0.03em;
    text-transform: none;
    padding: 4px 0;
    transition: color var(--transition-fast);
}

.nav-item--active .nav-link {
    color: var(--color-primary-accent);
}

.nav-link:hover,
.nav-link:focus {
    color: var(--color-primary-accent);
}

/* CTA Button in Header */

.header-cta {
    flex-shrink: 0;
}

.btn {
    display: inline-block;
    padding: 12px 28px;
    border-radius: var(--btn-radius);
    font-family: var(--font-body);
    font-size: 15px;
    font-weight: var(--font-weight-semibold);
    letter-spacing: 0.04em;
    text-transform: none;
    border: none;
    cursor: pointer;
    transition: background-color var(--transition-fast), color var(--transition-fast), box-shadow var(--transition-fast), transform var(--transition-fast);
}

.btn-primary {
    background-color: var(--color-primary-accent);
    color: var(--color-primary-900);
    box-shadow: 0 0 0 1px rgba(0, 0, 0, 0.12);
}

.btn-primary:hover,
.btn-primary:focus {
    background-color: #d4f830; /* slightly darker on hover */
    box-shadow: 0 2px 6px rgba(0, 0, 0, 0.35);
    transform: translateY(-1px);
}

.btn-primary:active {
    background-color: #c0e52b;
    box-shadow: 0 1px 2px rgba(0, 0, 0, 0.4);
    transform: translateY(0);
}

/* =============================
   FOOTER
   ============================= */

.site-footer {
    background-color: #111618;
    color: var(--color-neutral-000);
    border-top: 1px solid #242C2F;
    margin-top: auto;
}

.footer-main {
    display: flex;
    flex-wrap: wrap;
    gap: var(--space-xl);
    padding-top: var(--space-xl);
    padding-bottom: var(--space-lg);
}

.footer-branding {
    flex: 1 1 260px;
    max-width: 320px;
}

.footer-logo-text {
    display: flex;
    flex-direction: column;
    gap: 2px;
    margin-bottom: var(--space-sm);
}

.footer-logo-title {
    font-family: var(--font-heading);
    font-size: 18px;
    letter-spacing: 0.18em;
    text-transform: uppercase;
    color: var(--color-neutral-000);
}

.footer-logo-subtitle {
    font-family: var(--font-body);
    font-size: 10px;
    letter-spacing: 0.25em;
    text-transform: uppercase;
    color: var(--color-secondary-200);
}

.footer-copy-lead {
    font-size: 14px;
    color: var(--color-secondary-200);
    line-height: var(--line-height-relaxed);
}

.footer-links-grid {
    flex: 2 1 480px;
    display: grid;
    grid-template-columns: repeat(4, minmax(120px, 1fr));
    gap: var(--space-lg);
}

.footer-column {
    min-width: 0;
}

.footer-heading {
    font-family: var(--font-body);
    font-size: 14px;
    font-weight: var(--font-weight-semibold);
    letter-spacing: 0.15em;
    text-transform: uppercase;
    color: var(--color-secondary-200);
    margin-bottom: var(--space-xs);
}

.footer-link-list li + li {
    margin-top: 6px;
}

.footer-link-list a {
    font-size: 14px;
    color: var(--color-neutral-000);
    opacity: 0.85;
    transition: color var(--transition-fast), opacity var(--transition-fast);
}

.footer-link-list a:hover,
.footer-link-list a:focus {
    color: var(--color-primary-accent);
    opacity: 1;
}

.footer-bottom {
    border-top: 1px solid #242C2F;
    background-color: #0C1012;
}

.footer-bottom-inner {
    display: flex;
    align-items: center;
    justify-content: center;
    padding-top: var(--space-sm);
    padding-bottom: var(--space-sm);
}

.footer-bottom-text {
    font-size: 13px;
    color: var(--color-secondary-200);
}

/* =============================
   TYPOGRAPHY UTILITIES
   ============================= */

.text-small {
    font-size: var(--font-size-small);
}

.text-muted {
    color: var(--color-secondary-200);
}

.text-uppercase {
    text-transform: uppercase;
    letter-spacing: 0.12em;
}

/* =============================
   RESPONSIVE ADJUSTMENTS
   ============================= */

@media (max-width: 1024px) {
    .header-inner {
        height: auto;
        padding-top: var(--space-sm);
        padding-bottom: var(--space-sm);
        flex-wrap: wrap;
        gap: var(--space-sm);
    }

    .header-navigation {
        width: 100%;
        justify-content: space-between;
        gap: var(--space-md);
    }

    .nav-list {
        justify-content: flex-start;
        flex-wrap: wrap;
        row-gap: 6px;
        column-gap: var(--space-md);
    }

    .site-main {
        padding-top: var(--space-lg);
        padding-bottom: var(--space-lg);
    }

    .footer-main {
        padding-top: var(--space-lg);
        padding-bottom: var(--space-md);
    }

    .footer-links-grid {
        grid-template-columns: repeat(2, minmax(140px, 1fr));
    }
}

@media (max-width: 640px) {
    .header-inner {
        flex-direction: column;
        align-items: flex-start;
    }

    .header-navigation {
        flex-direction: column;
        align-items: flex-start;
    }

    .header-cta {
        align-self: stretch;
        text-align: center;
    }

    .btn {
        width: 100%;
        text-align: center;
    }

    .footer-main {
        flex-direction: column;
    }

    .footer-links-grid {
        grid-template-columns: 1fr 1fr;
    }

    .footer-bottom-inner {
        text-align: center;
    }
}
